func TestCacheFactorBug(t *testing.T) {
	// Test 1: All identical truthful string values should give cacheFactor=100
	p1 := NewProvider(true)
	for i := 0; i < 10; i++ {
		p1.MeasureSince("tmpl1", time.Now())
		p1.TrackValue("tmpl1", "same value")
	}
	var b1 bytes.Buffer
	p1.WriteMetrics(&b1)
	output1 := b1.String()
	t.Logf("Test 1 output:\n%s", output1)

	if !strings.Contains(output1, "100") {
		t.Errorf("Expected cacheFactor=100 for identical string values, got:\n%s", output1)
	}

	// Test 2: All identical template.HTML values should give cacheFactor=100
	p2 := NewProvider(true)
	for i := 0; i < 10; i++ {
		p2.MeasureSince("tmpl2", time.Now())
		p2.TrackValue("tmpl2", template.HTML("<div>same</div>"))
	}
	var b2 bytes.Buffer
	p2.WriteMetrics(&b2)
	output2 := b2.String()
	t.Logf("Test 2 output:\n%s", output2)

	if !strings.Contains(output2, "100") {
		t.Errorf("Expected cacheFactor=100 for identical template.HTML values, got:\n%s", output2)
	}

	// Test 3: Different values should give low cacheFactor (just verify it runs)
	p3 := NewProvider(true)
	for i := 0; i < 10; i++ {
		p3.MeasureSince("tmpl3", time.Now())
		p3.TrackValue("tmpl3", template.HTML(fmt.Sprintf("<div>page%d</div>", i)))
	}
	var b3 bytes.Buffer
	p3.WriteMetrics(&b3)
	output3 := b3.String()
	t.Logf("Test 3 output:\n%s", output3)
}

